{
  "children": [
    {
      "name": "RegisterPatient",
      "purpose": "Handle patient registration by validating required fields, creating a patient record, and generating a unique patient_id.",
      "behavior": "Validates that patient_data contains name, dob, contact, and insurance. If valid, creates a new patient record with a generated patient_id and stores it in the patients data store. Returns success with the patient_id or failure with an error message.",
      "stop_decompose": false,
      "stop_reason": ""
    },
    {
      "name": "BookAppointment",
      "purpose": "Handle appointment booking by checking patient existence, doctor availability, creating an appointment, and sending a confirmation.",
      "behavior": "Checks if the patient_id exists in the patients data store. If not, returns failure. Then checks doctor availability (simulated). If available, creates an appointment record in the appointments data store and sends a confirmation (simulated). Returns success with appointment details or failure with an error message.",
      "stop_decompose": false,
      "stop_reason": ""
    },
    {
      "name": "GetMedicalRecords",
      "purpose": "Retrieve all medical records for a patient, sorted by date descending.",
      "behavior": "Uses patient_id from patient_data to query the patients data store for associated medical records. Returns the records sorted by date descending, or an empty list if none exist.",
      "stop_decompose": false,
      "stop_reason": ""
    },
    {
      "name": "UpdatePatientProfile",
      "purpose": "Update patient profile fields and validate insurance against an external system.",
      "behavior": "Validates the patient_id exists in the patients data store. Updates the provided fields (name, dob, contact, insurance) in the patient record. Validates insurance by simulating a call to an external system. Returns success with updated profile or failure with an error message.",
      "stop_decompose": false,
      "stop_reason": ""
    }
  ],
  "decomposition_rationale": "The PatientPortal function block handles four distinct operations based on the command field. Each operation is independent and can be implemented as a separate child function. The parent function will parse the command and delegate to the appropriate child, ensuring no cross-calls between children. This decomposition keeps each child focused on a single responsibility, aligning with the functional requirements.",
  "dataflow_edges": [
    {
      "from_node": "parent",
      "from_output": "input.command",
      "to_node": "RegisterPatient",
      "to_input": "command",
      "note": "Parent routes to RegisterPatient when command is 'register'"
    },
    {
      "from_node": "parent",
      "from_output": "input.patient_data",
      "to_node": "RegisterPatient",
      "to_input": "patient_data",
      "note": "Patient data passed to registration"
    },
    {
      "from_node": "parent",
      "from_output": "input.command",
      "to_node": "BookAppointment",
      "to_input": "command",
      "note": "Parent routes to BookAppointment when command is 'book'"
    },
    {
      "from_node": "parent",
      "from_output": "input.patient_data",
      "to_node": "BookAppointment",
      "to_input": "patient_data",
      "note": "Patient data passed to booking"
    },
    {
      "from_node": "parent",
      "from_output": "input.command",
      "to_node": "GetMedicalRecords",
      "to_input": "command",
      "note": "Parent routes to GetMedicalRecords when command is 'records'"
    },
    {
      "from_node": "parent",
      "from_output": "input.patient_data",
      "to_node": "GetMedicalRecords",
      "to_input": "patient_data",
      "note": "Patient data passed to records retrieval"
    },
    {
      "from_node": "parent",
      "from_output": "input.command",
      "to_node": "UpdatePatientProfile",
      "to_input": "command",
      "note": "Parent routes to UpdatePatientProfile when command is 'update'"
    },
    {
      "from_node": "parent",
      "from_output": "input.patient_data",
      "to_node": "UpdatePatientProfile",
      "to_input": "patient_data",
      "note": "Patient data passed to profile update"
    },
    {
      "from_node": "RegisterPatient",
      "from_output": "output",
      "to_node": "parent",
      "to_input": "output",
      "note": "Result from registration returned to parent"
    },
    {
      "from_node": "BookAppointment",
      "from_output": "output",
      "to_node": "parent",
      "to_input": "output",
      "note": "Result from booking returned to parent"
    },
    {
      "from_node": "GetMedicalRecords",
      "from_output": "output",
      "to_node": "parent",
      "to_input": "output",
      "note": "Result from records retrieval returned to parent"
    },
    {
      "from_node": "UpdatePatientProfile",
      "from_output": "output",
      "to_node": "parent",
      "to_input": "output",
      "note": "Result from profile update returned to parent"
    }
  ]
}
